SELECT DISTINCT t.name
FROM tenants t
WHERE t.tenant_id IN (
    SELECT th.tenant_id
    FROM transaction_history th
);

SELECT SUM(i.qty) AS total_quantity
FROM inventory i
WHERE i.item_name = 'Item A';

SELECT SUM(qty) AS total_quantity
FROM inventory
WHERE item_name = 'Item A';

SELECT item_name, qty
FROM inventory
WHERE warehouse_id = 1 AND item_id = 0;
